module up_down_counter (  
    input wire clk,  
    input wire reset,  
    input wire up,  
    output reg [4-1:1-1] count  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            count <= 4'b0000;  
        end else if (up) begin  
            count <= count + 1;  
        end else begin  
            count <= count - 1;  
        end  
    end  
endmodule
